// filename: Database.java
import java.sql.*;
import java.util.*;
import java.util.logging.*;

public class Database {
    private static final Logger log = Logger.getLogger(Database.class.getName());
    private Connection conn;

    public Database() {
        try {
            conn = DriverManager.getConnection("jdbc:sqlite:" + GameConfig.DB_PATH);
            conn.createStatement().execute(
                "CREATE TABLE IF NOT EXISTS high_scores (" +
                "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                "player TEXT NOT NULL DEFAULT 'Player'," +
                "score INTEGER NOT NULL," +
                "played_at TEXT NOT NULL DEFAULT (datetime('now')))");
            log.info("DB ready");
        } catch (SQLException e) { log.severe(e.getMessage()); }
    }

    public void saveScore(String player, int score) {
        try (PreparedStatement ps = conn.prepareStatement(
                "INSERT INTO high_scores (player,score) VALUES (?,?)")) {
            ps.setString(1, player); ps.setInt(2, score); ps.executeUpdate();
        } catch (SQLException e) { log.warning(e.getMessage()); }
    }

    public List<String[]> getTopScores(int limit) {
        List<String[]> list = new ArrayList<>();
        try (PreparedStatement ps = conn.prepareStatement(
                "SELECT player,score,played_at FROM high_scores ORDER BY score DESC LIMIT ?")) {
            ps.setInt(1, limit);
            ResultSet rs = ps.executeQuery();
            while (rs.next()) list.add(new String[]{rs.getString(1),rs.getString(2),rs.getString(3)});
        } catch (SQLException e) { log.warning(e.getMessage()); }
        return list;
    }

    public void close() { try { if(conn!=null) conn.close(); } catch(SQLException ignored){} }
}
